import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Trash2 } from 'lucide-react';
import '../styles/Katalog.css';

const Keranjang = ({ keranjang, setKeranjang, isLoggedIn }) => {
  const [barangDipilih, setBarangDipilih] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    setBarangDipilih(keranjang.map(item => item.id));
  }, [keranjang]);

  const aturPilihBarang = (id) => {
    if (barangDipilih.includes(id)) {
      setBarangDipilih(barangDipilih.filter(itemId => itemId !== id));
    } else {
      setBarangDipilih([...barangDipilih, id]);
    }
  };

  const itemTerpilih = keranjang.filter(item => barangDipilih.includes(item.id));
  const totalHargaBelanja = itemTerpilih.reduce((total, item) => {
    const hargaAngka = parseInt(item.harga.replace(/[^0-9]/g, ''));
    return total + (hargaAngka * item.jumlah);
  }, 0);

  const handleAction = () => {
    if (!isLoggedIn) {
      navigate('/login');
    } else {
      const nomorAdmin = "6281234567890";
      let pesan = "Halo Admin CampBread, saya ingin memesan:\n\n";
      itemTerpilih.forEach((item, index) => {
        pesan += `${index + 1}. ${item.nama} (${item.jumlah}x)${item.catatan ? ` - Catatan: ${item.catatan}` : ''}\n`;
      });
      pesan += `\n*Total: Rp ${totalHargaBelanja.toLocaleString('id-ID')}*`;
      window.open(`https://wa.me/${nomorAdmin}?text=${encodeURIComponent(pesan)}`, '_blank');
    }
  };

  return (
    <div className="katalog-wrapper">
      <div className="katalog-overlay"></div>
      <div className="katalog-content" style={{ display: 'flex', gap: '30px' }}>
        <div style={{ flex: '2', background: 'white', borderRadius: '8px', border: '2px solid #38bdf8' }}>
          <div style={{ padding: '15px 20px', borderBottom: '1px solid #eee', display: 'flex', justifyContent: 'space-between' }}>
            <span>Keranjang Belanja</span>
            <span style={{ color: '#ef4444', fontWeight: 'bold', cursor: 'pointer' }} onClick={() => setKeranjang([])}>Hapus Semua</span>
          </div>
          <div style={{ padding: '0 20px' }}>
            {keranjang.map(item => (
              <div key={item.id} style={{ display: 'flex', alignItems: 'center', padding: '20px 0', borderBottom: '1px solid #eee', gap: '15px' }}>
                <input type="checkbox" checked={barangDipilih.includes(item.id)} onChange={() => aturPilihBarang(item.id)} />
                <img src={item.img} alt={item.nama} style={{ width: '80px', borderRadius: '8px' }} />
                <div style={{ flex: '1' }}>
                  <h4>{item.nama}</h4>
                  <p>{item.harga}</p>
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                  <span>{item.jumlah}x</span>
                  <Trash2 size={20} color="red" style={{ cursor: 'pointer' }} onClick={() => setKeranjang(keranjang.filter(i => i.id !== item.id))} />
                </div>
              </div>
            ))}
          </div>
        </div>
        <div style={{ flex: '1', background: 'white', borderRadius: '8px', padding: '25px', height: 'fit-content' }}>
          <h3>Ringkasan Belanja</h3>
          <div style={{ display: 'flex', justifyContent: 'space-between', margin: '20px 0' }}>
            <span>Total Belanja</span>
            <span style={{ fontWeight: 'bold' }}>Rp {totalHargaBelanja.toLocaleString('id-ID')}</span>
          </div>
          <button className="btn-add" style={{ width: '100%' }} onClick={handleAction}>
            {isLoggedIn ? "Konfirmasi Pesanan" : "Login untuk Checkout"}
          </button>
        </div>
      </div>
    </div>
  );
};

export default Keranjang;
